import { HTMLAttributes, ReactNode, forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";

export type CardVariant = "elevated" | "flat" | "outline";
export type CardSize = "sm" | "md" | "lg";
export type CardTone = "default" | "white" | "yellow" | "blue" | "black";

export type CardProps = {
  asChild?: boolean;
  children?: ReactNode;
  interactive?: boolean;
  withShadow?: boolean;
  variant?: CardVariant;
  size?: CardSize;
  tone?: CardTone;
} & HTMLAttributes<HTMLElement>;

const base =
  "group relative min-w-0 border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] text-[var(--sw-color-ink)]";

const shadowStyles: Record<CardSize, string> = {
  sm: "shadow-[4px_4px_0_var(--sw-color-shadow)]",
  md: "shadow-[8px_8px_0_var(--sw-color-shadow)]",
  lg: "shadow-[12px_12px_0_var(--sw-color-shadow)]",
};

const toneStyles: Record<CardTone, string> = {
  default: "bg-[var(--sw-color-paper)]",
  white: "bg-[var(--sw-color-surface)]",
  yellow: "bg-[var(--sw-color-yellow)]",
  blue: "bg-[var(--sw-color-blue)] text-white",
  black: "bg-[var(--sw-color-ink)] text-[var(--sw-color-surface)]",
};

const variantStyles: Record<CardVariant, string> = {
  elevated: "",
  flat: "shadow-none",
  outline: "bg-transparent shadow-none",
};

const interactiveStyles =
  "transition-all duration-150 hover:-translate-y-2 active:translate-y-2";

const interactiveShadowStyles =
  "hover:shadow-[12px_12px_0_var(--sw-color-shadow)] active:shadow-[4px_4px_0_var(--sw-color-shadow)]";

export const Card = forwardRef<HTMLElement, CardProps>(function Card({
  asChild = false,
  children,
  className,
  interactive = true,
  variant = "elevated",
  size = "md",
  tone = "default",
  withShadow,
  ...props
}, ref) {
  const Component = asChild ? Slot : "article";
  const resolvedWithShadow = withShadow ?? variant === "elevated";

  return (
    <Component
      ref={ref}
      className={cn(
        base,
        toneStyles[tone],
        variantStyles[variant],
        resolvedWithShadow && shadowStyles[size],
        interactive && interactiveStyles,
        interactive && resolvedWithShadow && interactiveShadowStyles,
        className,
      )}
      {...swirskiAttrs("card", { size, tone, variant })}
      {...props}
    >
      {children}
    </Component>
  );
});

Card.displayName = "Card";

import { HTMLAttributes, ReactNode, forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";

export type CardBadgeTone = "white" | "yellow" | "blue" | "red" | "black";
export type CardBadgeVariant = "solid" | "outline";
export type CardBadgeSize = "sm" | "md";
export type CardBadgePosition =
  | "top-left"
  | "top-right"
  | "bottom-left"
  | "bottom-right";

export type CardBadgeProps = {
  asChild?: boolean;
  children?: ReactNode;
  variant?: CardBadgeVariant;
  size?: CardBadgeSize;
  tone?: CardBadgeTone;
  position?: CardBadgePosition;
} & Omit<HTMLAttributes<HTMLSpanElement>, "color">;

const toneStyles: Record<CardBadgeTone, string> = {
  white: "bg-white text-black",
  yellow: "bg-[#FFD400] text-black",
  blue: "bg-[#0057FF] text-white",
  red: "bg-[#FF3131] text-white",
  black: "bg-[#0B0B0C] text-white",
};

const sizeStyles: Record<CardBadgeSize, string> = {
  sm: "px-2 py-1 text-sm",
  md: "px-3 py-1.5 text-base",
};

const positionStyles: Record<CardBadgePosition, string> = {
  "top-left": "left-3 top-3",
  "top-right": "right-3 top-3",
  "bottom-left": "bottom-3 left-3",
  "bottom-right": "bottom-3 right-3",
};

export const CardBadge = forwardRef<HTMLSpanElement, CardBadgeProps>(
  function CardBadge(
    {
      asChild = false,
      children,
      className,
      variant = "solid",
      size = "sm",
      tone = "white",
      position = "top-left",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "span";

    return (
      <Component
        ref={ref}
        className={cn(
          "absolute z-20 inline-flex w-fit max-w-[calc(100%-1.5rem)] -rotate-3 items-center border-2 border-black font-anton uppercase tracking-normal shadow-[2px_2px_0_#0B0B0C]",
          positionStyles[position],
          variant === "solid" ? toneStyles[tone] : "bg-transparent text-current",
          sizeStyles[size],
          className,
        )}
        {...swirskiAttrs("card-badge", { size, tone, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

CardBadge.displayName = "CardBadge";

import { HTMLAttributes, ReactNode, forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";

export type CardContentSize = "sm" | "md" | "lg";
export type CardContentVariant = "default" | "flush";

export type CardContentProps = {
  asChild?: boolean;
  children?: ReactNode;
  size?: CardContentSize;
  variant?: CardContentVariant;
} & HTMLAttributes<HTMLDivElement>;

const sizeStyles: Record<CardContentSize, string> = {
  sm: "p-4",
  md: "p-5",
  lg: "p-6",
};

export const CardContent = forwardRef<HTMLDivElement, CardContentProps>(
  function CardContent(
    {
      asChild = false,
      children,
      className,
      size = "md",
      variant = "default",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn(
          "min-w-0",
          variant === "default" && sizeStyles[size],
          className,
        )}
        {...swirskiAttrs("card-content", { size, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

CardContent.displayName = "CardContent";

import { CSSProperties, HTMLAttributes, ReactNode, forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";

export type CardMediaVariant = "default" | "flush";
export type CardMediaSize = "sm" | "md" | "lg";

export type CardMediaProps = {
  asChild?: boolean;
  children?: ReactNode;
  variant?: CardMediaVariant;
  size?: CardMediaSize;
  aspect?: string; // "4/3", "4/5"
} & Omit<HTMLAttributes<HTMLDivElement>, "color">;

export const CardMedia = forwardRef<HTMLDivElement, CardMediaProps>(
  function CardMedia(
    {
      asChild = false,
      children,
      className,
      aspect = "4/3",
      variant = "default",
      size = "md",
      style,
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn(
          "relative overflow-hidden bg-white",
          variant === "default" && "border-b-4 border-black",
          className,
        )}
        style={{ aspectRatio: aspect, ...(style as CSSProperties | undefined) }}
        {...swirskiAttrs("card-media", { size, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

CardMedia.displayName = "CardMedia";

