const toneStyles: Record<CardMetaTone, string> = {
  default: "text-current",
  muted: "text-[var(--sw-color-muted)]",
  inverted: "text-white",
};

export const CardMeta = forwardRef<HTMLDivElement, CardMetaProps>(
  function CardMeta(
    {
      asChild = false,
      children,
      className,
      variant = "default",
      size = "sm",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn(
