  variant?: CardTitleVariant;
  size?: CardTitleSize;
  tone?: CardTitleTone;
} & HTMLAttributes<HTMLHeadingElement>;

const sizeStyles: Record<CardTitleSize, string> = {
  sm: "text-2xl",
